class Solution:
    def addOperators(self, num: str, target: int) -> List[str]:
        res = []
        def dfs(i, path, val, last):
            if i == len(num):
                if val == target:
                    res.append(path)
                return
            for j in range(i, len(num)):
                if j > i and num[i] == '0':
                    break
                cur = int(num[i:j+1])
                if i == 0:
                    dfs(j+1, str(cur), cur, cur)
                else:
                    dfs(j+1, path+'+'+str(cur), val+cur, cur)
                    dfs(j+1, path+'-'+str(cur), val-cur, -cur)
                    dfs(j+1, path+'*'+str(cur), val-last+last*cur, last*cur)
        dfs(0, '', 0, 0)
        return res

